// src/pages/LoginPage.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useSensor';
import FingerprintAuth from '../components/auth/FingerprintAuth';
import './LoginPage.css';

const LoginPage = () => {
    const navigate = useNavigate();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [useFingerprint, setUseFingerprint] = useState(false);
    const [localError, setLocalError] = useState('');
    const [showFingerprintModal, setShowFingerprintModal] = useState(false);
    const [sensorConnected, setSensorConnected] = useState(false);
    const [isConnecting, setIsConnecting] = useState(false);
    const [scanStatus, setScanStatus] = useState(null);
    const [fingerprintResult, setFingerprintResult] = useState(null);
    
    const { login, loading, error } = useAuth();
    const { status: sensorStatus, connect, disconnect, isSupported } = useSensor();

    // Update sensor connected state
    useEffect(() => {
        console.log('Sensor status changed:', sensorStatus.connected);
        setSensorConnected(sensorStatus.connected);
        if (!sensorStatus.connected) {
            setUseFingerprint(false);
            setScanStatus(null);
        }
    }, [sensorStatus.connected]);

    // Listen for scan status updates from sensor
    useEffect(() => {
        if (!window.webSerialService) return;
        
        const handleScanStatus = (status) => {
            console.log('Scan status update:', status);
            setScanStatus(status);
            
            // If scan is successful, store the result and close modal
            if (status.status === 'success') {
                setFingerprintResult(status);
                // Auto-close modal after successful scan
                setTimeout(() => {
                    setShowFingerprintModal(false);
                    handleFingerprintSuccess(status);
                }, 1000);
            }
        };
        
        window.webSerialService.on('scan-status', handleScanStatus);
        
        return () => {
            window.webSerialService.off('scan-status', handleScanStatus);
        };
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLocalError('');
        setScanStatus(null);
        setFingerprintResult(null);

        if (!username) {
            setLocalError('Username is required');
            return;
        }

        if (useFingerprint) {
            // Check if sensor is connected
            if (!sensorConnected) {
                setLocalError('Please connect the fingerprint sensor first');
                return;
            }
            console.log('Opening fingerprint modal, sensor connected:', sensorConnected);
            setShowFingerprintModal(true);
        } else {
            if (!password) {
                setLocalError('Password is required');
                return;
            }
            const result = await login(username, password, false);
            if (!result.success) {
                setLocalError(result.error);
            }
        }
    };

    const handleFingerprintSuccess = async (result) => {
        console.log('Fingerprint success with result:', result);
        
        // The result contains the fingerprint ID from the sensor
        // result.userId is the fingerprint ID (e.g., 3)
        const fingerprintId = result.userId;
        
        if (!fingerprintId) {
            setLocalError('Fingerprint recognized but no ID found');
            return;
        }
        
        // Call login with fingerprint ID
        const loginResult = await login(username, null, true, fingerprintId);
        
        if (!loginResult.success) {
            setLocalError(loginResult.error);
            setScanStatus(null);
        } else {
            const user = JSON.parse(localStorage.getItem('user') || '{}');
            if (user.role === 'master_admin') {
                navigate('/admin');
            } else {
                navigate('/dashboard');
            }
        }
    };

    const handleFingerprintError = (error) => {
        console.log('Fingerprint error:', error);
        setShowFingerprintModal(false);
        setScanStatus(null);
        setFingerprintResult(null);
        setLocalError(error.message || 'Fingerprint authentication failed');
    };

    const handleConnectSensor = async () => {
        setIsConnecting(true);
        setLocalError('');
        
        try {
            const result = await connect();
            if (!result.success) {
                if (result.error?.includes('No port selected') || result.error?.includes('user cancelled')) {
                    setLocalError('No port selected. Please select a port to connect.');
                } else {
                    setLocalError(`Connection failed: ${result.error}`);
                }
            } else {
                setSensorConnected(true);
                setLocalError('');
                // Show success message briefly
                const successMsg = document.createElement('div');
                successMsg.className = 'success-message';
                successMsg.textContent = '✅ Sensor connected successfully!';
                document.querySelector('.login-container')?.prepend(successMsg);
                setTimeout(() => successMsg.remove(), 3000);
            }
        } catch (err) {
            setLocalError(`Connection error: ${err.message}`);
        } finally {
            setIsConnecting(false);
        }
    };

    const handleDisconnectSensor = () => {
        disconnect();
        setSensorConnected(false);
        setUseFingerprint(false);
        setScanStatus(null);
        setFingerprintResult(null);
        setLocalError('');
    };

    // Get scan status display
    const getScanStatusDisplay = () => {
        if (!scanStatus) return null;
        
        switch(scanStatus.status) {
            case 'waiting':
                return (
                    <div className="scan-status waiting">
                        <div className="scan-animation">
                            <div className="fingerprint-icon">👆</div>
                            <div className="pulse-wave"></div>
                        </div>
                        <div className="scan-message">
                            <strong>Waiting for fingerprint...</strong>
                            <p>Please place your finger on the sensor</p>
                        </div>
                    </div>
                );
            case 'detected':
                return (
                    <div className="scan-status detected">
                        <div className="scan-animation">
                            <div className="fingerprint-icon">🔍</div>
                        </div>
                        <div className="scan-message">
                            <strong>Fingerprint detected!</strong>
                            <p>Processing...</p>
                        </div>
                    </div>
                );
            case 'success':
                return (
                    <div className="scan-status success">
                        <div className="success-icon">✅</div>
                        <div className="scan-message">
                            <strong>Fingerprint recognized!</strong>
                            <p>Confidence: {scanStatus.confidence}%</p>
                            <p>Logging in...</p>
                        </div>
                    </div>
                );
            case 'failed':
                return (
                    <div className="scan-status failed">
                        <div className="error-icon">❌</div>
                        <div className="scan-message">
                            <strong>Fingerprint not recognized</strong>
                            <p>{scanStatus.instruction || 'Please try again'}</p>
                        </div>
                    </div>
                );
            default:
                return null;
        }
    };

    return (
        <div className="login-page">
            <div className="login-container">
                <h2>Login to E-Health System</h2>
                
                {/* Sensor Connection Section */}
                <div className="sensor-status-section">
                    {!isSupported ? (
                        <div className="sensor-warning">
                            ⚠️ Web Serial not supported. Please use Chrome or Edge browser.
                        </div>
                    ) : !sensorConnected ? (
                        <button 
                            type="button"
                            className="btn-connect"
                            onClick={handleConnectSensor}
                            disabled={isConnecting}
                        >
                            {isConnecting ? (
                                <>
                                    <span className="spinner"></span>
                                    Connecting...
                                </>
                            ) : (
                                '🔌 Connect USB Fingerprint Sensor'
                            )}
                        </button>
                    ) : (
                        <div className="sensor-badge">
                            <span className="sensor-dot"></span>
                            <span className="sensor-name">USB Fingerprint Sensor Connected</span>
                            <button 
                                type="button"
                                className="sensor-disconnect"
                                onClick={handleDisconnectSensor}
                            >
                                Disconnect
                            </button>
                        </div>
                    )}
                </div>

                {/* Error/Success Messages */}
                {(localError || error) && (
                    <div className="error-message">
                        <span className="error-icon">⚠️</span>
                        {localError || error}
                    </div>
                )}

                {/* Scan Status Display */}
                {showFingerprintModal && getScanStatusDisplay()}

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="username">Username</label>
                        <input
                            type="text"
                            id="username"
                            name="username"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            disabled={loading}
                            placeholder="Enter your username"
                            autoComplete="username"
                        />
                    </div>

                    {!useFingerprint && (
                        <div className="form-group">
                            <label htmlFor="password">Password</label>
                            <input
                                type="password"
                                id="password"
                                name="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                disabled={loading}
                                placeholder="Enter your password"
                                autoComplete="current-password"
                            />
                        </div>
                    )}

                    {sensorConnected && (
                        <div className="form-group">
                            <label className="checkbox-label">
                                <input
                                    type="checkbox"
                                    checked={useFingerprint}
                                    onChange={(e) => setUseFingerprint(e.target.checked)}
                                />
                                Use Fingerprint Authentication
                            </label>
                            {useFingerprint && (
                                <div className="fingerprint-tip">
                                    💡 Make sure your finger is clean and placed flat on the sensor
                                </div>
                            )}
                        </div>
                    )}

                    <button 
                        type="submit" 
                        className="btn btn-primary btn-block"
                        disabled={loading || (!useFingerprint && !password) || !username}
                    >
                        {loading ? (
                            <>
                                <span className="spinner"></span>
                                Processing...
                            </>
                        ) : (
                            useFingerprint ? '🔐 Login with Fingerprint' : 'Login'
                        )}
                    </button>
                </form>

                <div className="login-footer">
                    <p>Don't have an account? <a href="/register">Register here</a></p>
                    <p><a href="/">Back to Home</a></p>
                </div>
            </div>

            {/* Fingerprint Authentication Modal */}
            {showFingerprintModal && (
                <div className="modal-overlay" onClick={() => {
                    setShowFingerprintModal(false);
                    setScanStatus(null);
                    setFingerprintResult(null);
                }}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <button className="modal-close" onClick={() => {
                            setShowFingerprintModal(false);
                            setScanStatus(null);
                            setFingerprintResult(null);
                        }}>×</button>
                        <FingerprintAuth 
                            onSuccess={handleFingerprintSuccess}
                            onError={handleFingerprintError}
                            scanStatus={scanStatus}
                        />
                    </div>
                </div>
            )}
        </div>
    );
};

export default LoginPage;
